const input = $input.first().json || {};
function clean(v) { return String(v ?? '').trim(); }
function parseJsonSafe(v, fallback) {
  if (v && typeof v === 'object') return v;
  const s = clean(v);
  if (!s) return fallback;
  try { return JSON.parse(s); } catch { return fallback; }
}
function parseBool(v) {
  if (typeof v === 'boolean') return v;
  const s = clean(v).toLowerCase();
  return ['true','1','yes'].includes(s);
}
return [{ json: {
  mode: clean(input.mode || 'ONBOARDING').toUpperCase(),
  user_input: clean(input.user_input || input.text || input.message || ''),
  session_id: clean(input.session_id || input.chat_id || input.user_id || 'default-session'),
  current_state: Math.max(0, Math.min(40, Number.parseInt(input.current_state ?? '0', 10) || 0)),
  draft_json: parseJsonSafe(input.draft_json, {}),
  edit_target: clean(input.edit_target || ''),
  goal_slot_hint: clean(input.goal_slot_hint || '1'),
  intro_style: clean(input.intro_style || input.onboarding_style || 'coach').toLowerCase(),
  restart_onboarding: parseBool(input.restart_onboarding),
  today_bkk: $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd'),
  ts_bkk: $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd HH:mm:ss')
} }];

const data = $input.first().json || {};
const draft = data.draft_json || {};
const state = Number(data.current_state || 0);
const text = String(data.user_input || '').trim();
const hasOnboardingCheckpoint = Boolean(data.has_onboarding_checkpoint);

function yes(v) {
  return /^(ок|okay|ok|да|yes|go|поехали|погнали|старт|стартуем|начинаем|начнем|начнём|давай|давай начнем|давай начнём|хочу|хочу начать|готова|готов|готова начать|готов начать|готова к настройке|готов к настройке|переход к настройке|к настройке|настройка|перейти к настройке|перейдем к настройке|перейдём к настройке|запускай|запусти|запускаем|запустить|go ahead|lets go|let's go)$/i.test(String(v || '').trim());
}

function contractYes(v) {
  return /^(да|yes|подтверждаю|согласна|согласен|ок|готова|готов|да, подтверждаю)$/i.test(String(v || '').trim());
}

function buildContract(d) {
  const lines = [];
  lines.push('Вот что я зафиксировала в твоей игре.');
  if (d.bio) lines.push(`Состояние на старте: ${d.bio.body_state || d.bio.energy_state || 'зафиксировано'}.`);
  if (d.sprint?.days) lines.push(`Спринт: ${d.sprint.days} дней.`);
  if (d.goal?.goal_name) lines.push(`Цель уровня: ${d.goal.goal_name}.`);
  if (d.goal?.treasure) lines.push(`Treasure: ${d.goal.treasure}.`);
  if (d.level_rules?.money_net_monthly_threshold != null && d.level_rules?.money_net_monthly_threshold !== '') lines.push(`Money Net для апа уровня: ${d.level_rules.money_net_monthly_threshold} THB в месяц 3 месяца подряд.`);
  if (Array.isArray(d.level_names) && d.level_names.length) lines.push(`Уровни: ${d.level_names.join(', ')}.`);
  lines.push('Если все верно, напиши: да, подтверждаю. Если хочешь поправить блок, напиши его название: био, реальность, спринт, задачи, привычки, KPI, цель, боссы, recovery, магазин, уровни или money net.');
  return lines.join(' ');
}

function detectContractBackState(v) {
  const s = String(v || '').toLowerCase();
  if (/био|цикл|энерг|тело/i.test(s)) return 2;
  if (/реаль|день|обязатель|нагруз/i.test(s)) return 6;
  if (/спринт|ритм/i.test(s)) return 9;
  if (/задач|track|craft|social|vitality/i.test(s)) return 11;
  if (/привыч/i.test(s)) return 17;
  if (/kpi/i.test(s)) return 23;
  if (/цель|treasure|горизонт/i.test(s)) return 26;
  if (/босс|stuck|штраф/i.test(s)) return 30;
  if (/recovery|hp|сло/i.test(s)) return 35;
  if (/магаз|наград/i.test(s)) return 36;
  if (/уров|level/i.test(s)) return 37;
  if (/money|net|доход|денежн|порог|threshold/i.test(s)) return 38;
  return null;
}

