if (!text) {
  return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', reply_to_user: prompts[state] || prompts[0], onboarding_complete: false } }];
}

if (state === 0) {
  if (!yes(text)) {
    if (hasOnboardingCheckpoint && text) {
      return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', current_state: 1, reply_to_user: prompts[1], onboarding_complete: false } }];
    }
    return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', current_state: 0, reply_to_user: introPrompt, onboarding_complete: false } }];
  }
  return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', current_state: 1, reply_to_user: prompts[1], onboarding_complete: false } }];
}

if (state === 1) {
  return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', current_state: 2, reply_to_user: prompts[2], onboarding_complete: false } }];
}

if (state === 29) {
  return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', current_state: 30, reply_to_user: prompts[30], onboarding_complete: false } }];
}

if (state === 39) {
  if (contractYes(text)) {
    return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ACTIVATE', onboarding_complete: false } }];
  }
  const backState = detectContractBackState(text);
  if (backState != null) {
    return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', current_state: backState, reply_to_user: prompts[backState], onboarding_complete: false } }];
  }
  return [{ json: { ...data, flow_kind: 'ONBOARDING', action: 'ASK', current_state: 39, reply_to_user: buildContract(draft), onboarding_complete: false } }];
}

