rules.push(ruleRow({ rule_group:'COMMIT', type:'TACTICAL_RULE', id_name:'onboarding_commit', rpg_name:'Onboarding Commit', value:'ACTIVE', target_json: jsonString({contract_confirmed:true}), desc:'Commit accepted at onboarding', notes:'TACTICAL_RULE:COMMIT' }));

logs.push(logRow({ event_type:'RULE_CREATED', entity_group:'GAME_RULES', entity_id:'onboarding_batch', entity_name:'Onboarding Rules Batch', status:'SUCCESS', value:String(rules.length), comment:'Initial rules created from onboarding' }));
logs.push(logRow({ event_type:'COMMIT_LOG', entity_group:'COMMIT', entity_id:'onboarding_commit', entity_name:'Onboarding Commit', status:'ACCEPTED', context_json: jsonString({session_id:data.session_id}) }));
logs.push(logRow({ event_type:'ATTEMPT_STARTED', entity_group:'ATTEMPT', entity_id:'1', entity_name:'Attempt 1', status:'ACTIVE', attempt_id:'1', context_json: jsonString({started_from:'onboarding', xp_total_at_start:0}) }));
logs.push(logRow({ event_type:'ONBOARDING_COMPLETED', entity_group:'ONBOARDING', entity_id:data.session_id, entity_name:'Onboarding', status:'COMPLETED', attempt_id:'1', context_json: jsonString({goal:draft.goal || null, bio:draft.bio || null, reality:draft.reality || null, level_rules:draft.level_rules || null}) }));

return [{ json: { ...data, current_state: 40, draft_json: draft, onboarding_complete: true, game_rules_rows: rules, game_log_rows: logs, reply_to_user: 'Игра активирована. Я зафиксировала правила, запустила первую попытку и теперь могу помочь разложить твою первую цель на понятные шаги.', handoff: { suggest_goal_decomposition: true, goal_slot_hint: String(data.goal_slot_hint || '1') } } }];

const data = $input.first().json || {};
const extracted = data.extracted_json || {};
const relevant = Array.isArray(data.relevant_rules) ? data.relevant_rules : [];
const ts = data.ts_bkk || $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd HH:mm:ss');
function slug(v) { return String(v || '').toLowerCase().normalize('NFKD').replace(/[^\p{L}\p{N}]+/gu, '_').replace(/^_+|_+$/g, '').slice(0, 80) || 'item'; }
function jsonString(v) { return JSON.stringify(v || {}, null, 0); }
let sortOrder = 1;
function ruleRow({rule_group, type='TACTICAL_RULE', id_name, rpg_name, track='', value='', resource_type='', target_value='', period='', target_json='', desc='', source='GAME_RULES_WORKFLOW', notes=''}) {
  return [ts, true, rule_group, type, id_name, rpg_name, track, '', '', '', value, resource_type, target_value, period, target_json, '', '', '', '', desc, source, sortOrder++, notes];
}
function logRow(comment) {
  return [[ts, 'RULE_UPDATED', 'GAME_RULES_WORKFLOW', 'GAME_RULES', extracted.target_group || '', extracted.target_group || '', '', 'UPDATED', '', '', '', '', data.today_bkk, '', '', '1', jsonString({target_group: extracted.target_group || '', items: extracted.replacement_items || []}), comment]];
}
const ruleClass = String(extracted.rule_class || '').toUpperCase();
if (ruleClass === 'BASE_RULE') {
  return [{ json: { ...data, guarded: true, reply_to_user: extracted.reply_hint || 'Это базовое правило. Его нельзя менять напрямую — такой запрос надо вести через therapist / reframe flow.', game_log_rows: [] } }];
}
const items = Array.isArray(extracted.replacement_items) ? extracted.replacement_items.filter(Boolean) : [];
const targetGroup = String(extracted.target_group || '').toUpperCase();
if (!targetGroup || !items.length) {
  return [{ json: { ...data, guarded: true, reply_to_user: 'Не смогла собрать точный patch для правила. Напиши, что именно хочешь изменить, чуть конкретнее.', game_log_rows: [] } }];
}
const deactivate_updates = relevant.map(rule => ({ range: `GAME_RULES!C${rule.row_number}`, values: [[false]] }));
const new_rule_rows = [];
if (targetGroup === 'SPRINT') {
  const item = items[0] || {};
  new_rule_rows.push(ruleRow({ rule_group:'SPRINT', id_name:'sprint_length', rpg_name:'Sprint Length', value:String(item.days || item.value || ''), resource_type:'DAY', target_value:String(item.days || item.value || ''), period:'SPRINT', target_json: jsonString(item), desc:'Updated sprint rule', notes:'TACTICAL_RULE:SPRINT' }));
}
if (targetGroup === 'KPI') {
  items.forEach(item => new_rule_rows.push(ruleRow({ rule_group:'KPI', id_name:slug(item.name), rpg_name:item.name || 'KPI', track:'CRAFT', value:String(item.reward_xp_gold ?? item.value ?? ''), resource_type:'XP_Gold', target_value:String(item.target_value ?? ''), period:item.period || 'SPRINT', target_json: jsonString(item), desc:'Updated KPI rule', notes:'TACTICAL_RULE:KPI' })));
}
if (targetGroup === 'HABIT') {
  items.forEach(item => {
    const track = String(item.track || '').toUpperCase();
    const resource = track === 'VITALITY' ? 'HP' : (track === 'SOCIAL' ? 'RULE_DEFINED' : 'XP_Gold');
    new_rule_rows.push(ruleRow({ rule_group:'HABIT', id_name:slug(item.name), rpg_name:item.name || 'Habit', track, value:String(item.reward_value ?? item.value ?? ''), resource_type:resource, target_value:String(item.target_value ?? ''), period:item.period || 'DAY', target_json: jsonString(item), desc:'Updated habit rule', notes:'TACTICAL_RULE:HABIT' }));
  });
}
if (targetGroup === 'TASK') {
  items.forEach(item => new_rule_rows.push(ruleRow({ rule_group:'TASK', id_name:slug(item.name), rpg_name:item.name || 'Task', track:String(item.track || '').toUpperCase(), value:String(item.value ?? ''), resource_type:item.resource_type || 'RULE_DEFINED', target_json: jsonString(item), desc:'Updated task rule', notes:'TACTICAL_RULE:TASK' })));
}
if (targetGroup === 'SHOP') {
  items.forEach(item => new_rule_rows.push(ruleRow({ rule_group:'SHOP', id_name:slug(item.name), rpg_name:item.name || 'Reward', value:String(-Math.abs(Number(item.cost || item.value || 0))), resource_type:'XP_Gold', target_json: jsonString(item), desc:'Updated shop rule', notes:'TACTICAL_RULE:SHOP' })));
}
if (targetGroup === 'GOAL') {
  const item = items[0] || {};
  new_rule_rows.push(ruleRow({ rule_group:'GOAL', id_name:'current_level_goal', rpg_name:item.goal_name || item.name || 'Goal', value:String(item.horizon_days ?? ''), resource_type:'DAY', target_json: jsonString(item), desc:'Updated goal rule', notes:'TACTICAL_RULE:GOAL' }));
}
if (targetGroup === 'LEVEL_NAME') {
  items.forEach((item, idx) => new_rule_rows.push(ruleRow({ rule_group:'LEVEL_NAME', id_name:`level_${idx+1}`, rpg_name:item.name || item.rpg_name || `Level ${idx+1}`, target_json: jsonString(item), desc:'Updated level name', notes:'TACTICAL_RULE:LEVEL_NAME' })));
}
if (targetGroup === 'BOSS') {
  items.forEach(item => new_rule_rows.push(ruleRow({ rule_group:'BOSS', id_name:slug(item.name), rpg_name:item.name || 'Boss', track:String(item.track || '').toUpperCase(), value:String(item.penalty_value ?? item.value ?? ''), resource_type:item.resource_type || 'XP_Gold', target_json: jsonString(item), desc:'Updated boss rule', notes:'TACTICAL_RULE:BOSS' })));
}
if (!new_rule_rows.length) {
  return [{ json: { ...data, guarded: true, reply_to_user: 'Пока поддерживаю только tactical edits для спринта, KPI, привычек, задач, магазина, цели, уровней и текущих боссов.', game_log_rows: [] } }];
}
return [{ json: { ...data, guarded: false, deactivate_updates, new_rule_rows, game_log_rows: logRow(extracted.reply_hint || 'Tactical rule updated'), reply_to_user: extracted.reply_hint || 'Тактическое правило обновлено.' } }];

const data = $('Build Onboarding Checkpoint').first().json
  || $('Append Activation GAME_LOG').first().json
  || $('Rules Edit Build Patch').first().json
  || $input.first().json
  || {};
const message = data.reply_to_user || data.response_to_agent || data.error_message || 'Сейчас не удалось собрать следующий шаг онбординга. Попробуй еще раз.';
return [{ json: {
  ok: data.ok !== false,
  error_message: data.error_message || '',
  current_state: data.current_state ?? 0,
  draft_json: data.draft_json ?? {},
  reply_to_user: message,
  onboarding_complete: Boolean(data.onboarding_complete),
  handoff: data.handoff || { suggest_goal_decomposition: false, goal_slot_hint: '' },
  response_to_agent: message
} }];
